class Solution:
    def assignElements(self, groups, elements):
        max_g = max(groups)
        best_idx = [-1] * (max_g + 1)
        seen = set()
        for j, v in enumerate(elements):
            if v > max_g or v in seen:
                continue
            seen.add(v)
            for m in range(v, max_g + 1, v):
                if best_idx[m] == -1:
                    best_idx[m] = j
        return [best_idx[g] for g in groups]

