var assignElements = function(groups, elements) {
    const maxG = Math.max(...groups);
    const bestIdx = new Array(maxG + 1).fill(-1);
    const seen = new Set();
    for (let j = 0; j < elements.length; j++) {
        const v = elements[j];
        if (v > maxG || seen.has(v)) continue;
        seen.add(v);
        for (let m = v; m <= maxG; m += v) {
            if (bestIdx[m] === -1) bestIdx[m] = j;
        }
    }
    return groups.map(g => bestIdx[g]);
};
